import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.util.stream.Collectors;

@Component
public class OidcAuthenticationFilter extends OncePerRequestFilter {

    public static final String SESSION_USER_KEY = "OIDC_USER_SESSION";

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    HttpServletResponse response,
                                    FilterChain filterChain) throws ServletException, IOException {
        Object sessionUser = request.getSession(false) != null ? request.getSession(false).getAttribute(SESSION_USER_KEY) : null;
        if (sessionUser instanceof OidcUserSession oidcUserSession &&
                SecurityContextHolder.getContext().getAuthentication() == null) {
            OidcAuthenticationToken authentication = new OidcAuthenticationToken(
                    oidcUserSession,
                    oidcUserSession.getAuthorities().stream().map(SimpleGrantedAuthority::new).collect(Collectors.toList())
            );
            SecurityContextHolder.getContext().setAuthentication(authentication);
        }
        filterChain.doFilter(request, response);
    }
}

package com.example.oidc.service;

import com.example.oidc.config.OidcClientSettings;
import com.example.oidc.model.OidcTokenResponse;
import com.example.oidc.model.OidcUserSession;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.StringUtils;
import org.springframework.web.client.RestTemplate;

import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.*;

@Service
public class OidcService {

    private final OidcClientSettings settings;
    private final RestTemplate restTemplate;
    private final ObjectMapper objectMapper;

    public OidcService(OidcClientSettings settings, RestTemplate restTemplate, ObjectMapper objectMapper) {
        this.settings = settings;
        this.restTemplate = restTemplate;
        this.objectMapper = objectMapper;
    }

    public String buildAuthorizationUrl(HttpSession session) {
        String state = UUID.randomUUID().toString();
        String nonce = UUID.randomUUID().toString();
        session.setAttribute("OIDC_STATE", state);
        session.setAttribute("OIDC_NONCE", nonce);

        return settings.getAuthorizationUri()
                + "?response_type=code"
                + "&client_id=" + urlEncode(settings.getClientId())
                + "&redirect_uri=" + urlEncode(settings.getRedirectUri())
                + "&scope=" + urlEncode(settings.getScope())
                + "&state=" + urlEncode(state)
                + "&nonce=" + urlEncode(nonce);
    }

    public OidcUserSession handleCallback(String code, String state, HttpSession session) {
        String expectedState = (String) session.getAttribute("OIDC_STATE");
        String expectedNonce = (String) session.getAttribute("OIDC_NONCE");

        if (!StringUtils.hasText(expectedState) || !expectedState.equals(state)) {
            throw new IllegalArgumentException("Invalid OIDC state");
        }

        OidcTokenResponse tokenResponse = exchangeAuthorizationCode(code);
        Map<String, Object> idTokenClaims = parseAndValidateIdToken(tokenResponse.getId_token(), expectedNonce);
        Map<String, Object> userInfoClaims = fetchUserInfo(tokenResponse.getAccess_token());

        String subject = stringClaim(idTokenClaims, "sub");
        String username = firstNonBlank(
                stringClaim(userInfoClaims, "preferred_username"),
                stringClaim(idTokenClaims, "preferred_username"),
                stringClaim(userInfoClaims, "name"),
                stringClaim(idTokenClaims, "name"),
                subject
        );
        String email = firstNonBlank(
                stringClaim(userInfoClaims, "email"),
                stringClaim(idTokenClaims, "email")
        );

        List<String> authorities = new ArrayList<>();
        authorities.add("ROLE_USER");

        OidcUserSession userSession = new OidcUserSession(
                subject,
                username,
                email,
                tokenResponse.getAccess_token(),
                tokenResponse.getId_token(),
                tokenResponse.getRefresh_token(),
                idTokenClaims,
                userInfoClaims,
                authorities
        );

        session.setAttribute("OIDC_USER_SESSION", userSession);
        session.removeAttribute("OIDC_STATE");
        session.removeAttribute("OIDC_NONCE");
        return userSession;
    }

    public OidcTokenResponse exchangeAuthorizationCode(String code) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(List.of(MediaType.APPLICATION_JSON));
        headers.setBasicAuth(settings.getClientId(), settings.getClientSecret(), StandardCharsets.UTF_8);

        LinkedMultiValueMap<String, String> form = new LinkedMultiValueMap<>();
        form.add("grant_type", "authorization_code");
        form.add("code", code);
        form.add("redirect_uri", settings.getRedirectUri());

        HttpEntity<LinkedMultiValueMap<String, String>> request = new HttpEntity<>(form, headers);
        ResponseEntity<OidcTokenResponse> response = restTemplate.exchange(
                settings.getTokenUri(),
                HttpMethod.POST,
                request,
                OidcTokenResponse.class
        );

        if (!response.getStatusCode().is2xxSuccessful() || response.getBody() == null) {
            throw new IllegalStateException("Failed to exchange authorization code for tokens");
        }

        return response.getBody();
    }

    public Map<String, Object> fetchUserInfo(String accessToken) {
        if (!StringUtils.hasText(settings.getUserInfoUri()) || !StringUtils.hasText(accessToken)) {
            return Collections.emptyMap();
        }

        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        headers.setAccept(List.of(MediaType.APPLICATION_JSON));

        HttpEntity<Void> request = new HttpEntity<>(headers);
        ResponseEntity<Map> response = restTemplate.exchange(
                settings.getUserInfoUri(),
                HttpMethod.GET,
                request,
                Map.class
        );

        if (!response.getStatusCode().is2xxSuccessful() || response.getBody() == null) {
            return Collections.emptyMap();
        }

        return response.getBody();
    }

    public Map<String, Object> parseAndValidateIdToken(String idToken, String expectedNonce) {
        if (!StringUtils.hasText(idToken)) {
            throw new IllegalArgumentException("Missing id_token");
        }

        String[] parts = idToken.split("\\.");
        if (parts.length < 2) {
            throw new IllegalArgumentException("Invalid JWT format");
        }

        String payloadJson = new String(Base64.getUrlDecoder().decode(parts[1]), StandardCharsets.UTF_8);
        Map<String, Object> claims;
        try {
            claims = objectMapper.readValue(payloadJson, new TypeReference<>() {});
        } catch (Exception e) {
            throw new IllegalArgumentException("Unable to parse id_token claims", e);
        }

        validateStandardClaims(claims, expectedNonce);
        return claims;
    }

    private void validateStandardClaims(Map<String, Object> claims, String expectedNonce) {
        String issuer = stringClaim(claims, "iss");
        String audience = extractAudience(claims.get("aud"));
        Long exp = longClaim(claims, "exp");
        String nonce = stringClaim(claims, "nonce");

        if (StringUtils.hasText(settings.getIssuer()) && !settings.getIssuer().equals(issuer)) {
            throw new IllegalArgumentException("Invalid issuer");
        }

        if (!settings.getClientId().equals(audience)) {
            Object aud = claims.get("aud");
            if (aud instanceof Collection<?> collection) {
                boolean found = collection.stream().anyMatch(v -> settings.getClientId().equals(String.valueOf(v)));
                if (!found) {
                    throw new IllegalArgumentException("Invalid audience");
                }
            } else {
                throw new IllegalArgumentException("Invalid audience");
            }
        }

        if (exp == null || Instant.ofEpochSecond(exp).isBefore(Instant.now())) {
            throw new IllegalArgumentException("Expired id_token");
        }

        if (StringUtils.hasText(expectedNonce) && !expectedNonce.equals(nonce)) {
            throw new IllegalArgumentException("Invalid nonce");
        }
    }

    private String extractAudience(Object aud) {
        if (aud instanceof String s) {
            return s;
        }
        if (aud instanceof Collection<?> collection && !collection.isEmpty()) {
            return String.valueOf(collection.iterator().next());
        }
        return null;
    }

    private String stringClaim(Map<String, Object> claims, String key) {
        Object value = claims.get(key);
        return value != null ? String.valueOf(value) : null;
    }

    private Long longClaim(Map<String, Object> claims, String key) {
        Object value = claims.get(key);
        if (value instanceof Number number) {
            return number.longValue();
        }
        if (value instanceof String s && StringUtils.hasText(s)) {
            return Long.parseLong(s);
        }
        return null;
    }

    private String firstNonBlank(String... values) {
        for (String value : values) {
            if (StringUtils.hasText(value)) {
                return value;
            }
        }
        return null;
    }

    private String urlEncode(String value) {
        return java.net.URLEncoder.encode(value, StandardCharsets.UTF_8);
    }
}

package com.example.oidc.controller;

import com.example.oidc.model.OidcUserSession;
import com.example.oidc.security.OidcAuthenticationFilter;
import com.example.oidc.service.OidcService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.MediaType;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.LinkedHashMap;
import java.util.Map;

@RestController
public class OidcController {

    private final OidcService oidcService;

    public OidcController(OidcService oidcService) {
        this.oidcService = oidcService;
    }

    @GetMapping(value = "/", produces = MediaType.APPLICATION_JSON_VALUE)
    public Map<String, Object> home(Authentication authentication, HttpServletRequest request) {
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("authenticated", authentication != null && authentication.isAuthenticated());
        response.put("login", "/login");
        response.put("logout", "/logout");

        HttpSession session = request.getSession(false);
        if (session != null) {
            Object user = session.getAttribute(OidcAuthenticationFilter.SESSION_USER_KEY);
            response.put("sessionUser", user);
        }
        return response;
    }

    @GetMapping("/login")
    public void login(HttpServletRequest request, jakarta.servlet.http.HttpServletResponse response) throws java.io.IOException {
        String authorizationUrl = oidcService.buildAuthorizationUrl(request.getSession(true));
        response.sendRedirect(authorizationUrl);
    }

    @GetMapping("/oidc/callback")
    public void callback(String code, String state, HttpServletRequest request, jakarta.servlet.http.HttpServletResponse response) throws java.io.IOException {
        OidcUserSession userSession = oidcService.handleCallback(code, state, request.getSession(true));
        response.sendRedirect("/me");
    }

    @GetMapping(value = "/me", produces = MediaType.APPLICATION_JSON_VALUE)
    public Object me(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) {
            return Map.of("authenticated", false);
        }
        Object user = session.getAttribute(OidcAuthenticationFilter.SESSION_USER_KEY);
        if (user == null) {
            return Map.of("authenticated", false);
        }
        return user;
    }
}

package com.example.oidc.controller;

import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(Exception.class)
    public org.springframework.http.ResponseEntity<Map<String, Object>> handle(Exception ex) {
        return org.springframework.http.ResponseEntity.status(HttpStatus.BAD_REQUEST)
                .body(Map.of(
                        "error", ex.getClass().getSimpleName(),
                        "message", ex.getMessage()
                ));
    }
}

